function setup() {
  const button = document.getElementById('myButton');

  function handleClick() {
    console.log('Clicked');
  }

  button.addEventListener('click', handleClick);

  // Later, when you want to remove the listener:
  return () => {
    button.removeEventListener('click', handleClick);
  };
}

const cleanup = setup();
// When needed
cleanup();

function Log(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    console.log(`Calling ${propertyKey} with args:`, args);
    const result = originalMethod.apply(this, args);
    console.log(`Method ${propertyKey} returned:`, result);
    return result;
  };
  return descriptor;
}

class Calculator {
  @Log
  add(a: number, b: number): number {
    return a + b;
  }
}

const calc = new Calculator();
calc.add(5, 7);

function Debounce(ms: number) {
  return function (target: any, propertyKey: string, descriptor: PropertyDescriptor) {
    const originalMethod = descriptor.value;
    let timeout: ReturnType<typeof setTimeout> | null = null;

    descriptor.value = function (...args: any[]) {
      if (timeout) clearTimeout(timeout);
      timeout = setTimeout(() => {
        originalMethod.apply(this, args);
      }, ms);
    };

    return descriptor;
  };
}

class Search {
  @Debounce(300)
  filter(query: string) {
    console.log(`Searching for: ${query}`);
  }
}

const search = new Search();
search.filter('a');
search.filter('ab');
search.filter('abc');  // Only this call triggers after 300ms

function Required(target: any, propertyKey: string) {
  let value: any;
  const getter = () => value;
  const setter = (newVal: any) => {
    if (newVal === null || newVal === undefined || newVal === '') {
      throw new Error(`${propertyKey} is required`);
    }
    value = newVal;
  };
  Object.defineProperty(target, propertyKey, {
    get: getter,
    set: setter,
    enumerable: true,
    configurable: true
  });
}

class User {
  @Required
  name!: string;
}

const user = new User();
try {
  user.name = '';
} catch (err) {
  console.error(err.message);  // Outputs: name is required
}

function Entity(tableName: string) {
  return function (constructor: Function) {
    constructor.prototype._tableName = tableName;
  };
}

@Entity('users')
class UserEntity {
  id!: number;
  name!: string;
}

const userEntity = new UserEntity();
console.log(userEntity._tableName);  // Output: users

function printId(id: number | string) {
  if (typeof id === "string") {
    // TypeScript knows `id` is string here
    console.log(id.toUpperCase());
  } else {
    // Otherwise, `id` must be a number
    console.log(id.toFixed(2));
  }
}

printId("abc123");
printId(42);

class Dog {
  bark() {
    console.log("Woof!");
  }
}

class Cat {
  meow() {
    console.log("Meow!");
  }
}

function speak(pet: Dog | Cat) {
  if (pet instanceof Dog) {
    pet.bark(); // Narrowed to Dog
  } else {
    pet.meow(); // Narrowed to Cat
  }
}

const myDog = new Dog();
speak(myDog);

interface Fish {
  swim(): void;
}

interface Bird {
  fly(): void;
}

function isFish(pet: Fish | Bird): pet is Fish {
  return (pet as Fish).swim !== undefined;
}

function move(pet: Fish | Bird) {
  if (isFish(pet)) {
    pet.swim(); // Narrowed to Fish
  } else {
    pet.fly(); // Narrowed to Bird
  }
}

function printUsername(username: string | null) {
  if (username) {
    // username is narrowed to string (not null)
    console.log("Username is - " + username.toUpperCase());
  } else {
    console.log("No username provided.");
  }
}

class MyContextManager:
    def __enter__(self):
        print('Entering the context')
        return self

    def __exit__(self, exc_type, exc_value, traceback):
        print('Exiting the context')
        if exc_type:
            print(f'An exception occurred: {exc_value}')
        # Returning False re-raises the exception if any
        return False

with MyContextManager() as manager:
    print('Inside the with block')

from contextlib import contextmanager

@contextmanager
def my_context():
    print('Start of context')
    try:
        yield
    finally:
        print('End of context')

with my_context():
    print('Inside with block')

